def _swap_dim_labels(da):
    src_dims = [d for d in da.dims if d.endswith(Lbl.SRC)]
    rng_dims = [d for d in da.dims if d.endswith(Lbl.RNG)]
    rename_dict = {d: d.replace(Lbl.SRC, Lbl.RNG) for d in src_dims} | {d: d.replace(Lbl.RNG, Lbl.SRC) for d in rng_dims}
    return da.rename(rename_dict)

# %% ../../nbs/api/pymor/operators.ipynb
def _is_labeled_da(da):
    if not isinstance(da, DataArray): return False
    return any(d.endswith(Lbl.SRC) or d.endswith(Lbl.RNG) for d in da.dims)

