class XarrayMatrixOperator(XarrayMatrixBasedOperator):
    """An `Operator` backed by an xarray `DataArray`."""

    def __init__(
        self, 
        matrix:DataArray|ndarray|SparseArray|sparray, # N-dimensional matrix
        source:XarrayVectorSpace|DataArray|Coordinates|dict|list|str|None=None, # Source vector space or coordinates
        range:XarrayVectorSpace|DataArray|Coordinates|dict|list|str|None=None, # Range vector space or coordinates
        solver_options:dict=None, # Options for matrix solver
        name:str=None # Operator name
    ):
        if issparse(matrix): matrix = sparse(matrix)
        if not isinstance(matrix, DataArray):
            if not isinstance(source, XarrayVectorSpace): 
                if isinstance(source, str): source = [source]
                if source is not None: 
                    source = validate_coord_data(source, matrix.shape[-len(source):])
                source = XarrayVectorSpace(source)
            if not isinstance(range, XarrayVectorSpace):
                if isinstance(range, str): range = [range]
                if range is not None:
                    range = validate_coord_data(range, matrix.shape[:len(range)])
                range = XarrayVectorSpace(range)
            labeled_source = _label_dims_with(source, Lbl.SRC)
            labeled_range = _label_dims_with(range, Lbl.RNG)
            matrix = DataArray(
                matrix, 
                dims=labeled_range.dims + labeled_source.dims,
                coords=make_coordinates(labeled_range.coord_data | labeled_source.coord_data),
                name=name
            )
        else:
            if not _is_labeled_da(matrix): matrix = _label_dims(matrix, source, range)
            coords = validate_coord_data(matrix)
            labeled_source = XarrayVectorSpace({k:v for k,v in coords.items() if k.endswith(Lbl.SRC)})
            labeled_range = XarrayVectorSpace({k:v for k,v in coords.items() if k.endswith(Lbl.RNG)})
            source = unlabel_dims(labeled_source)
            range = unlabel_dims(labeled_range)
        if name is None: name = matrix.name
        self.__auto_init(locals())
        self.labeled_source = labeled_source
        self.labeled_range = labeled_range

    def assemble(self, mu=None): return self

    @property
    def size(self):
        return self.matrix.size
        
    @property
    def sparse(self):
        return isinstance(self.matrix.data, SparseArray)

