@match_class(IdentityOperator)
def expand_IdentityOperator(self, op):
    if not isinstance(op.source, XarrayVectorSpace): return op
    return ProductOperator([IdentityOperator(XarrayVectorSpace({k:v})) for k,v in op.space.coord_data.items()])

#| export
ExpandRules.insert_rule(-1, expand_IdentityOperator)

